#!/usr/bin/env python3
"""
kaching-tell fix applier
Run from the repo root:  python3 apply_kaching_tell_fixes.py
Backs up each original to <file>.bak before overwriting.
"""
import base64, os, sys, shutil

FILES = {
    'src/utils/score.js': "",
    'src/detection/goalDetector.js': "",
    'src/detection/verifier.js': "",
    'src/ledger/store.js': "",
    'src/index.js': "",
    'src/anchor/anchor.js': "",
    'src/config/constants.js': "",
    'scripts/replay.js': "",
    'scripts/simulate.js': "",
}

def main():
    if not os.path.isdir('src') or not os.path.isdir('scripts'):
        print('ERROR: run this from the kaching-tell repo root (where src/ and scripts/ live).')
        sys.exit(1)
    for path, b64 in FILES.items():
        data = base64.b64decode(b64)
        os.makedirs(os.path.dirname(path), exist_ok=True)
        if os.path.exists(path):
            shutil.copy2(path, path + '.bak')
            tag = '(backed up .bak)'
        else:
            tag = '(new file)'
        with open(path, 'wb') as fh:
            fh.write(data)
        print('wrote', path, tag)
    print('')
    print('Done. Next:')
    print('  npm install')
    print('  node scripts/simulate.js      # offline proof, no creds needed')
    print('  node scripts/replay.js        # lists fixtures; then re-run with the France vs England id')

if __name__ == '__main__':
    main()
